"use client";

import Link from "next/link";
import { useCallback, useEffect, useMemo, useState } from "react";
import { businessContextSearchParams, readStoredBusinessContext, readStoredDataClass, writeStoredBusinessContext, type StoredBusinessContext } from "@/features/operating-model/client-context";
import { BusinessEntityMultiSelect } from "@/components/BusinessEntitySelect";

type Owner = { id: string; name: string; roles: string[] };
type Project = { id: string; name: string; projectLevel: string | null; progress: number; status: string; health: string; openSignals: number };
type Center = {
  summary: Record<string, number | null>;
  exceptionInbox: Array<{ id: string; projectId: string | null; title: string; severity: string; status: string; dueAt: string | null; route?: string }>;
  portfolioHealth: Project[];
  projectsWithoutLevel: Project[];
  dependencies: Array<{ id: string; fromProjectId: string; toProjectId: string; dependencyType?: string; description?: string; status: string; ownerUserId?: string; dueDate: string | null; resolutionCriteria?: string }>;
  capacityConflicts: Array<{ id: string; ownerName: string; capacityHours: number; demandHours: number; periodStart: string }>;
  capacityConflictActions: Array<{ id: string; ownerName?: string; ownerUserId: string; actionTitle: string; overloadHours: number; dueAt: string; status: string }>;
  dataQualityIssues: Array<{ id: string; projectId: string | null; fieldName?: string | null; description?: string; severity: string; status: string; ownerUserId?: string | null; dueAt: string | null }>;
  cadences: Array<{ id: string; cadenceType: string; status: string; periodStart: string; periodEnd: string; conclusions?: unknown[]; actionCount?: number; openActionCount?: number }>;
  governanceActions: Array<{ id: string; cadenceId: string; projectId: string | null; title: string; ownerUserId: string; dueAt: string; status: string }>;
  ruleMatrices: Array<{ id: string; version: string; status: string; rules: Record<string, unknown>; changeReason: string; effectiveFrom: string | null }>;
  metricDefinitions: Array<{ id: string; metricKey: string; version: string; name: string; definition: string; freshnessSlaMinutes: number | null; status: string }>;
  eligibleOwners: Owner[];
};

type WorkDraft = { comment: string; evidence: string[]; summary: string; actionPlan: string };
type CapacityWeek = { period_start: string; period_end: string; capacity_hours: string; allocations: Record<string, string> };
type MeetingAction = { title: string; description: string; owner_user_id: string; project_id: string; due_at: string };
type SignalRuleEditor = { signalType: string; metricRef: string; comparison: string; yellowThreshold: string; redThreshold: string; unit: string; impactDimensions: string; dataFreshnessHours: string; handlingRole: string; slaStartEvent: string; slaEndEvent: string; escalationLevel: string; decisionAuthority: string; closureEvidence: string };
type LevelRuleEditor = { maxOpenCriticalSignals: string; cadence: string; escalationHours: string; evidenceRequired: boolean; signalRules: SignalRuleEditor[] };

const LEVELS = ["S", "A", "B", "C"] as const;
const SIGNAL_TYPES = ["milestone_delay", "progress", "cost", "quality", "risk", "resource", "acceptance", "cash", "benefit", "data_quality"] as const;
const EMPTY_SIGNAL_RULE: SignalRuleEditor = { signalType: "", metricRef: "", comparison: "greater_than", yellowThreshold: "", redThreshold: "", unit: "", impactDimensions: "", dataFreshnessHours: "", handlingRole: "", slaStartEvent: "", slaEndEvent: "", escalationLevel: "", decisionAuthority: "", closureEvidence: "" };

function weekPeriod() {
  const date = new Date();
  const day = date.getDay() || 7;
  const monday = new Date(date); monday.setDate(date.getDate() - day + 1);
  const sunday = new Date(monday); sunday.setDate(monday.getDate() + 6);
  return { start: monday.toLocaleDateString("sv-SE"), end: sunday.toLocaleDateString("sv-SE") };
}

function buildWeeks(projects: Project[], count = 8): CapacityWeek[] {
  const date = new Date();
  const day = date.getDay() || 7;
  const monday = new Date(date); monday.setDate(date.getDate() - day + 1);
  return Array.from({ length: count }, (_, index) => {
    const start = new Date(monday); start.setDate(monday.getDate() + index * 7);
    const end = new Date(start); end.setDate(start.getDate() + 6);
    return { period_start: start.toLocaleDateString("sv-SE"), period_end: end.toLocaleDateString("sv-SE"), capacity_hours: "40", allocations: Object.fromEntries(projects.map(project => [project.id, "0"])) };
  });
}

function evidenceFrom(value: string[]) {
  return value.map((sourceId, index) => ({ sourceType: "supabase_record", sourceId, title: `闭环证据 ${index + 1}` }));
}

function nextStatus(status: string, kind: "quality" | "governance" | "capacity" | "dependency") {
  const maps = {
    quality: { open: "assigned", assigned: "in_progress", reopened: "in_progress", in_progress: "evidence_submitted" },
    governance: { assigned: "accepted", accepted: "in_progress", in_progress: "evidence_submitted", reopened: "evidence_submitted" },
    capacity: { assigned: "accepted", accepted: "in_progress", in_progress: "evidence_submitted", reopened: "evidence_submitted" },
    dependency: { identified: "confirmed", confirmed: "monitoring", monitoring: "evidence_submitted", blocked: "evidence_submitted", reopened: "monitoring" },
  } as const;
  return (maps[kind] as Record<string, string>)[status] || "";
}

function ownerName(owners: Owner[], id?: string | null) {
  return owners.find(owner => owner.id === id)?.name || id || "待明确";
}

export default function PmoControlCenterPage() {
  const period = useMemo(() => weekPeriod(), []);
  const [context, setContext] = useState<StoredBusinessContext | null>(null);
  const [actorUserId, setActorUserId] = useState("");
  const [center, setCenter] = useState<Center | null>(null);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [saving, setSaving] = useState(false);
  const [workDrafts, setWorkDrafts] = useState<Record<string, WorkDraft>>({});
  const [cadence, setCadence] = useState({ period_start: period.start, period_end: period.end, cadence_type: "weekly_portfolio" });
  const [meetingConclusions, setMeetingConclusions] = useState<Record<string, string>>({});
  const [meetingActions, setMeetingActions] = useState<Record<string, MeetingAction[]>>({});
  const [meetingDecisionBriefs, setMeetingDecisionBriefs] = useState<Record<string, string>>({});
  const [dependency, setDependency] = useState({ from_project_id: "", to_project_id: "", dependency_type: "deliverable", description: "", owner_user_id: "", due_date: period.end, resolution_criteria: "" });
  const [capacity, setCapacity] = useState({ owner_name: "", owner_user_id: "", role_name: "" });
  const [capacityWeeks, setCapacityWeeks] = useState<CapacityWeek[]>([]);
  const [metric, setMetric] = useState({ metric_key: "", version: "", name: "", definition: "", numerator_definition: "", denominator_definition: "", source_type: "", field_or_formula: "", unit: "", freshness_sla_minutes: "", activate: true });
  const [ruleVersion, setRuleVersion] = useState("");
  const [ruleReason, setRuleReason] = useState("");
  const [rules, setRules] = useState<Record<typeof LEVELS[number], LevelRuleEditor>>(() => Object.fromEntries(LEVELS.map(level => [level, { maxOpenCriticalSignals: "", cadence: "", escalationHours: "", evidenceRequired: true, signalRules: [{ ...EMPTY_SIGNAL_RULE }] }])) as Record<typeof LEVELS[number], LevelRuleEditor>);
  const [ruleLoaded, setRuleLoaded] = useState(false);

  const draftFor = (id: string): WorkDraft => workDrafts[id] ?? { comment: "", evidence: [], summary: "", actionPlan: "" };
  const updateDraft = (id: string, patch: Partial<WorkDraft>) => setWorkDrafts(previous => ({ ...previous, [id]: { ...draftFor(id), ...patch } }));

  const load = useCallback(async () => {
    setError("");
    try {
      const response = await fetch("/api/context/current", { cache: "no-store" });
      const body = await response.json() as { available_contexts?: Array<{ id: string; businessRole: string; orgId: string; subjectScope: string; subjectId: string; status: string }> };
      if (!response.ok) throw new Error("无法读取业务身份");
      const stored = readStoredBusinessContext();
      const ownerMode = typeof window !== "undefined" && new URLSearchParams(window.location.search).get("owner_mode") === "1";
      const selected = body.available_contexts?.find(item => item.id === stored?.assignmentId && item.status === "active" && (ownerMode || item.businessRole === "pmo"))
        ?? body.available_contexts?.find(item => item.status === "active" && (ownerMode || item.businessRole === "pmo"));
      if (!selected) throw new Error(ownerMode ? "当前账号没有有效业务角色。" : "当前账号没有有效的 PMO 业务角色，请由管理员先分配管理范围。");
      const active = { assignmentId: selected.id, businessRole: selected.businessRole, orgId: selected.orgId, subjectScope: selected.subjectScope, subjectId: selected.subjectId };
      writeStoredBusinessContext(active); setContext(active);
      const query = businessContextSearchParams(active, readStoredDataClass());
      const result = await fetch(`/api/pmo/control-center?${query.toString()}`, { cache: "no-store" });
      const payload = await result.json();
      if (!result.ok) throw new Error(payload.detail || payload.error || "PMO控制中心加载失败");
      const loaded = payload.center as Center;
      setCenter(loaded); setActorUserId(String(payload.actor_user_id || ""));
      setDependency(previous => ({ ...previous, from_project_id: previous.from_project_id || loaded.portfolioHealth[0]?.id || "", to_project_id: previous.to_project_id || loaded.portfolioHealth[1]?.id || "", owner_user_id: previous.owner_user_id || loaded.eligibleOwners[0]?.id || "" }));
      setCapacity(previous => ({ ...previous, owner_user_id: previous.owner_user_id || loaded.eligibleOwners[0]?.id || "", owner_name: previous.owner_name || loaded.eligibleOwners[0]?.name || "" }));
      setCapacityWeeks(previous => previous.length === 0 ? buildWeeks(loaded.portfolioHealth) : previous);
      if (!ruleLoaded && loaded.ruleMatrices.length > 0) {
        const matrix = loaded.ruleMatrices.find(item => item.status === "active") ?? loaded.ruleMatrices[0];
        const restored = Object.fromEntries(LEVELS.map(level => {
          const source = (matrix.rules[level] ?? {}) as Record<string, unknown>;
          const signalRules = Array.isArray(source.signalRules) ? source.signalRules as Array<Record<string, unknown>> : [];
          return [level, { maxOpenCriticalSignals: String(source.maxOpenCriticalSignals ?? ""), cadence: String(source.cadence ?? ""), escalationHours: String(source.escalationHours ?? ""), evidenceRequired: source.evidenceRequired !== false, signalRules: signalRules.length ? signalRules.map(rule => ({ signalType: String(rule.signalType ?? ""), metricRef: `${String(rule.metricKey ?? "")}@@${String(rule.metricVersion ?? "")}`, comparison: String(rule.comparison ?? "greater_than"), yellowThreshold: String(rule.yellowThreshold ?? ""), redThreshold: String(rule.redThreshold ?? ""), unit: String(rule.unit ?? ""), impactDimensions: Array.isArray(rule.impactDimensions) ? rule.impactDimensions.join("、") : "", dataFreshnessHours: String(rule.dataFreshnessHours ?? ""), handlingRole: String(rule.handlingRole ?? ""), slaStartEvent: String(rule.slaStartEvent ?? ""), slaEndEvent: String(rule.slaEndEvent ?? ""), escalationLevel: String(rule.escalationLevel ?? ""), decisionAuthority: String(rule.decisionAuthority ?? ""), closureEvidence: Array.isArray(rule.closureEvidence) ? rule.closureEvidence.join("、") : "" })) : [{ ...EMPTY_SIGNAL_RULE }] }];
        })) as Record<typeof LEVELS[number], LevelRuleEditor>;
        setRules(restored); setRuleVersion(matrix.version); setRuleLoaded(true);
      }
    } catch (caught) { setError(caught instanceof Error ? caught.message : "PMO控制中心加载失败"); }
  }, [ruleLoaded]);

  useEffect(() => { const timer = window.setTimeout(() => void load(), 0); return () => window.clearTimeout(timer); }, [load]);

  async function save(operation: string, payload: Record<string, unknown>) {
    if (!context) return;
    setSaving(true); setError(""); setMessage("");
    try {
      const query = businessContextSearchParams(context, readStoredDataClass());
      const response = await fetch(`/api/pmo/control-center?${query.toString()}`, { method: "POST", headers: { "Content-Type": "application/json", "Idempotency-Key": crypto.randomUUID() }, body: JSON.stringify({ operation, ...payload }) });
      const body = await response.json();
      if (!response.ok) throw new Error(Array.isArray(body.detail) ? body.detail.join("；") : body.detail || body.error || "保存失败");
      setMessage("业务动作已原子保存，责任人、deadline、证据和审计事件已同步记录。"); await load();
    } catch (caught) { setError(caught instanceof Error ? caught.message : "保存失败"); } finally { setSaving(false); }
  }

  async function scanManagementSignals() {
    if (!context) return;
    setSaving(true); setError(""); setMessage("");
    try {
      const query = businessContextSearchParams(context, readStoredDataClass());
      const response = await fetch(`/api/management/signals/scan?${query.toString()}`, { method: "POST" });
      const body = await response.json() as { created?: number; refreshed?: number; warnings?: string[]; detail?: string; error?: string };
      if (!response.ok) throw new Error(body.detail || body.error || "管理信号扫描失败");
      const warnings = Array.isArray(body.warnings) && body.warnings.length > 0 ? `；${body.warnings.join("；")}` : "";
      setMessage(`管理信号扫描完成：新增 ${body.created ?? 0} 条，刷新 ${body.refreshed ?? 0} 条${warnings}`);
      await load();
    } catch (caught) { setError(caught instanceof Error ? caught.message : "管理信号扫描失败"); } finally { setSaving(false); }
  }

  async function routeSignal(id: string) {
    if (!context) return;
    setSaving(true); setError("");
    try {
      const response = await fetch(`/api/management/signals/${id}/escalate`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ business_role: context.businessRole, comment: draftFor(id).comment || "PMO已审查信号并按影响路由" }) });
      const body = await response.json(); if (!response.ok) throw new Error(body.warning || body.detail || body.error || "信号路由失败");
      setMessage("信号已路由为纠偏行动或上报决策候选。"); await load();
    } catch (caught) { setError(caught instanceof Error ? caught.message : "信号路由失败"); } finally { setSaving(false); }
  }

  const statLabels: Record<string, string> = { activeProjects: "在管项目", classifiedProjects: "已分级项目", projectLevelCoverageRate: "分级覆盖率%", redSignals: "红色信号", overdueSignals: "逾期信号", blockedDependencies: "阻断依赖", overAllocatedResources: "超载快照", overdueDataQuality: "逾期数据治理", preparingCadences: "运行中会议", openGovernanceActions: "会后行动", openCapacityConflicts: "资源冲突行动", activeRuleMatrices: "生效规则矩阵", activeMetricDefinitions: "生效指标" };
  const isPmo = context?.businessRole === "pmo";
  const projectsById = new Map(center?.portfolioHealth.map(project => [project.id, project.name]) ?? []);

  function WorkFields({ id, summary = false, actionPlan = false }: { id: string; summary?: boolean; actionPlan?: boolean }) {
    const draft = draftFor(id);
    return <div style={{ display: "grid", gap: 7, marginTop: 9 }}>
      {summary && <textarea className="input" rows={2} placeholder="填写纠偏或完成摘要" value={draft.summary} onChange={event => updateDraft(id, { summary: event.target.value })} />}
      {actionPlan && <textarea className="input" rows={2} placeholder="填写具体处置方案" value={draft.actionPlan} onChange={event => updateDraft(id, { actionPlan: event.target.value })} />}
      <BusinessEntityMultiSelect kind="evidence" value={draft.evidence} onChange={evidence => updateDraft(id, { evidence })} placeholder="选择本次处置证据"/>
      <input className="input" placeholder="复核意见、退回原因或效果结论" value={draft.comment} onChange={event => updateDraft(id, { comment: event.target.value })} />
    </div>;
  }

  function ownerCanAct(ownerId?: string | null) { return Boolean(ownerId && ownerId === actorUserId); }

  return <main style={{ minHeight: "100vh", background: "var(--bg)" }}>
    <header style={{ padding: "15px 28px", borderBottom: "1px solid var(--border)", background: "var(--surface)", display: "flex", gap: 14, alignItems: "center", flexWrap: "wrap" }}>
      <Link href="/" style={{ color: "var(--text2)", textDecoration: "none" }}>← 返回首页</Link><strong style={{ color: "var(--purple)" }}>{isPmo ? "PMO组合治理与运营控制中心" : "我的治理行动"}</strong><span className="tag tag-purple">真实业务闭环</span><Link href="/collaboration-inbox" className="btn-secondary" style={{ textDecoration: "none", marginLeft: "auto" }}>返回协作待办</Link>
    </header>
    <div style={{ maxWidth: 1500, margin: "0 auto", padding: 28 }}>
      {(error || message) && <section className="card" style={{ marginBottom: 16, borderColor: error ? "rgba(239,68,68,.4)" : "rgba(16,185,129,.4)", color: error ? "var(--red)" : "var(--green)" }}>{error || message}</section>}
      {center && <>
        {isPmo && <section style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(145px,1fr))", gap: 10, marginBottom: 18 }}>{Object.entries(center.summary).map(([key, value]) => <div className="stat-card" key={key}><div className="stat-num">{value ?? "暂无"}</div><div className="stat-label">{statLabels[key] || key}</div></div>)}</section>}

        {isPmo && <div style={{ display: "grid", gridTemplateColumns: "1.1fr .9fr", gap: 16, alignItems: "start" }}>
          <section className="card"><div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 10, flexWrap: "wrap" }}><div className="section-title">🚨 PMO异常收件箱</div><button className="btn-secondary" disabled={saving} onClick={() => void scanManagementSignals()}>按生效规则扫描九类信号</button></div><p style={{ color: "var(--text2)", fontSize: ".76rem", lineHeight: 1.6 }}>只读取当前范围的真实指标事实；没有生效规则、可信数据或责任人时会明确停止，不生成绿色展示数据。</p>{center.exceptionInbox.length === 0 ? <p style={{ color: "var(--text2)" }}>当前范围没有未关闭管理信号。</p> : center.exceptionInbox.map(item => <article key={item.id} style={{ padding: 11, background: "var(--surface2)", borderRadius: 10, marginTop: 8 }}><div style={{ display: "flex", justifyContent: "space-between", gap: 10 }}><strong>{item.title}</strong><span className={`tag ${item.severity === "critical" ? "tag-red" : "tag-amber"}`}>{item.severity}</span></div><p style={{ color: "var(--text2)", marginTop: 6, fontSize: ".78rem" }}>{item.status} · deadline {item.dueAt || "待明确"}</p>{["verified", "under_review"].includes(item.status) && <><input className="input" style={{ marginTop: 8 }} placeholder="PMO审查意见" value={draftFor(item.id).comment} onChange={event => updateDraft(item.id, { comment: event.target.value })}/><button className="btn-primary" style={{ marginTop: 8 }} disabled={saving} onClick={() => void routeSignal(item.id)}>升级或纠偏</button></>}{item.status === "pending_decision_brief" && <Link href="/decision-center" className="btn-primary" style={{ display: "inline-block", marginTop: 8, textDecoration: "none" }}>形成 CEO 决策包</Link>}</article>)}</section>
          <section className="card"><div className="section-title">📊 组合健康</div>{center.portfolioHealth.map(project => <article key={project.id} style={{ padding: 10, borderTop: "1px solid var(--border)" }}><div style={{ display: "flex", justifyContent: "space-between" }}><Link href={`/projects/${project.id}?role=pmo&data_class=${readStoredDataClass()}`} style={{ color: "var(--text)", textDecoration: "none", fontWeight: 800 }}>{project.name}</Link><span className={`tag ${project.health === "red" ? "tag-red" : project.health === "yellow" ? "tag-amber" : "tag-green"}`}>{project.health}</span></div><p style={{ color: "var(--text2)", fontSize: ".76rem", marginTop: 5 }}>{project.projectLevel || "未分级"}级 · {project.progress}% · 开放信号 {project.openSignals}</p></article>)}</section>
        </div>}

        {isPmo && <section className="card" style={{ marginTop: 16 }}><div style={{ display: "flex", justifyContent: "space-between", gap: 10, alignItems: "center", flexWrap: "wrap" }}><div className="section-title">🗓️ 治理会议闭环</div><button className="btn-secondary" disabled={saving} onClick={() => void save("scan_data_quality", {})}>扫描并生成数据治理任务</button></div><div style={{ display: "grid", gridTemplateColumns: "repeat(2,minmax(0,1fr))", gap: 14 }}>
          <div><h3 style={{ fontSize: ".9rem" }}>新建治理节奏</h3><select className="input" value={cadence.cadence_type} onChange={event => setCadence({ ...cadence, cadence_type: event.target.value })}><option value="weekly_portfolio">周组合会</option><option value="monthly_operating">月经营会</option><option value="quarterly_portfolio">季度组合审查</option><option value="daily_exception">紧急例外会</option></select><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginTop: 8 }}><input className="input" type="date" value={cadence.period_start} onChange={event => setCadence({ ...cadence, period_start: event.target.value })}/><input className="input" type="date" value={cadence.period_end} onChange={event => setCadence({ ...cadence, period_end: event.target.value })}/></div><button className="btn-primary" disabled={saving} style={{ marginTop: 10 }} onClick={() => void save("create_cadence", cadence)}>创建治理会议</button></div>
          <div><h3 style={{ fontSize: ".9rem" }}>治理流程入口</h3><p style={{ color: "var(--text2)", lineHeight: 1.7 }}>立项、阶段门、风险升级、变更、验收和结项仍由标准治理流程运营，此处统一聚合例外、会议和会后行动。</p><Link href="/governance-workflows" className="btn-secondary" style={{ textDecoration: "none", display: "inline-block", marginTop: 8 }}>进入治理流程工作区</Link></div>
        </div></section>}

        {isPmo && center.cadences.length > 0 && <section className="card" style={{ marginTop: 16 }}><div className="section-title">📝 会议结论与行动</div><div style={{ display: "grid", gap: 12 }}>{center.cadences.map(item => {
          const actions = meetingActions[item.id] ?? [{ title: "", description: "", owner_user_id: center.eligibleOwners[0]?.id || "", project_id: center.portfolioHealth[0]?.id || "", due_at: `${item.periodEnd}T18:00` }];
          const transition = item.status === "preparing" ? "ready" : item.status === "ready" ? "in_meeting" : item.status === "in_meeting" ? "minutes_pending" : item.status === "actions_pending" ? "effect_review" : item.status === "effect_review" ? "closed" : "";
          return <article key={item.id} style={{ border: "1px solid var(--border)", borderRadius: 12, padding: 12 }}><div style={{ display: "flex", justifyContent: "space-between", gap: 8, flexWrap: "wrap" }}><strong>{item.cadenceType} · {item.periodStart} 至 {item.periodEnd}</strong><span className="tag tag-blue">{item.status} · 开放行动 {item.openActionCount ?? 0}</span></div>
            {item.status === "in_meeting" && <textarea className="input" rows={3} style={{ marginTop: 9 }} placeholder="每行一条会议结论" value={meetingConclusions[item.id] || ""} onChange={event => setMeetingConclusions(previous => ({ ...previous, [item.id]: event.target.value }))}/>}
            {item.status === "minutes_pending" && <div style={{ marginTop: 9 }}><p style={{ color: "var(--text2)", fontSize: ".8rem" }}>每项行动必须有责任人和 deadline。</p>{actions.map((action, index) => <div key={index} style={{ display: "grid", gridTemplateColumns: "1.4fr 1fr 1fr 1fr", gap: 7, marginTop: 7 }}><input className="input" placeholder="行动标题" value={action.title} onChange={event => setMeetingActions(previous => ({ ...previous, [item.id]: actions.map((entry, i) => i === index ? { ...entry, title: event.target.value } : entry) }))}/><select className="input" value={action.owner_user_id} onChange={event => setMeetingActions(previous => ({ ...previous, [item.id]: actions.map((entry, i) => i === index ? { ...entry, owner_user_id: event.target.value } : entry) }))}>{center.eligibleOwners.map(owner => <option key={owner.id} value={owner.id}>{owner.name}</option>)}</select><select className="input" value={action.project_id} onChange={event => setMeetingActions(previous => ({ ...previous, [item.id]: actions.map((entry, i) => i === index ? { ...entry, project_id: event.target.value } : entry) }))}>{center.portfolioHealth.map(project => <option key={project.id} value={project.id}>{project.name}</option>)}</select><input className="input" type="datetime-local" value={action.due_at} onChange={event => setMeetingActions(previous => ({ ...previous, [item.id]: actions.map((entry, i) => i === index ? { ...entry, due_at: event.target.value } : entry) }))}/></div>)}<button className="btn-secondary" style={{ marginTop: 7 }} onClick={() => setMeetingActions(previous => ({ ...previous, [item.id]: [...actions, { title: "", description: "", owner_user_id: center.eligibleOwners[0]?.id || "", project_id: center.portfolioHealth[0]?.id || "", due_at: `${item.periodEnd}T18:00` }] }))}>新增行动</button></div>}
            {item.status === "effect_review" && <input className="input" style={{ marginTop: 9 }} placeholder="填写会议闭环效果结论" value={draftFor(item.id).comment} onChange={event => updateDraft(item.id, { comment: event.target.value })}/>}<div style={{ display: "flex", gap: 8, marginTop: 9, flexWrap: "wrap" }}>
              {transition && <button className="btn-primary" disabled={saving || (item.status === "in_meeting" && !meetingConclusions[item.id]?.trim()) || (item.status === "effect_review" && !draftFor(item.id).comment.trim())} onClick={() => void save("transition_cadence", { id: item.id, to_status: transition, conclusions: item.status === "in_meeting" ? (meetingConclusions[item.id] || "").split("\n").filter(Boolean).map(summary => ({ type: "conclusion", summary })) : [], effect_review: item.status === "effect_review" ? { outcome: "effective", summary: draftFor(item.id).comment } : {} })}>{item.status === "preparing" ? "冻结输入并就绪" : item.status === "ready" ? "开始会议" : item.status === "in_meeting" ? "确认会议结论" : item.status === "actions_pending" ? "进入效果复核" : "关闭治理会议"}</button>}
              {item.status === "minutes_pending" && <><button className="btn-primary" disabled={saving || actions.some(action => !action.title || !action.owner_user_id || !action.due_at)} onClick={() => void save("transition_cadence", { id: item.id, to_status: "actions_pending", actions: actions.map(action => ({ ...action, due_at: new Date(action.due_at).toISOString() })) })}>生成会后行动</button><button className="btn-secondary" disabled={saving} onClick={() => void save("transition_cadence", { id: item.id, to_status: "effect_review", conclusions: [...(item.conclusions ?? []), { type: "no_action", summary: "会议结论经人工确认无需后续处理" }], comment: "会议结论确认无需后续行动" })}>确认无需处理</button><input className="input" style={{ width: 250 }} placeholder="已提交决策包ID" value={meetingDecisionBriefs[item.id] || ""} onChange={event => setMeetingDecisionBriefs(previous => ({ ...previous, [item.id]: event.target.value }))}/><button className="btn-secondary" disabled={saving || !meetingDecisionBriefs[item.id]?.trim()} onClick={() => void save("transition_cadence", { id: item.id, to_status: "effect_review", conclusions: [...(item.conclusions ?? []), { type: "decision", decision_brief_id: meetingDecisionBriefs[item.id], summary: "会议结论已转正式决策包" }], comment: "已核验并关联正式决策包" })}>关联决策包</button><Link href="/decision-center" className="btn-secondary" style={{ textDecoration: "none" }}>去创建决策包</Link></>}
            </div></article>;
        })}</div></section>}

        <section className="card" style={{ marginTop: 16 }}><div className="section-title">🧹 数据质量纠偏闭环</div>{center.dataQualityIssues.length === 0 ? <p style={{ color: "var(--text2)" }}>当前没有开放数据质量任务。</p> : <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(300px,1fr))", gap: 10 }}>{center.dataQualityIssues.map(item => { const next = nextStatus(item.status, "quality"); return <article key={item.id} style={{ padding: 12, border: "1px solid var(--border)", borderRadius: 10 }}><div style={{ display: "flex", justifyContent: "space-between", gap: 8 }}><strong>{item.fieldName || "数据质量"}</strong><span className="tag tag-amber">{item.severity} · {item.status}</span></div><p style={{ color: "var(--text2)", marginTop: 6 }}>{item.description}</p><p style={{ fontSize: ".75rem", color: "var(--text3)", marginTop: 5 }}>责任人：{ownerName(center.eligibleOwners, item.ownerUserId)} · deadline {item.dueAt || "待明确"}</p><WorkFields id={item.id} summary />
          <div style={{ display: "flex", gap: 7, marginTop: 8, flexWrap: "wrap" }}>{next && ownerCanAct(item.ownerUserId) && <button className="btn-primary" disabled={saving || (next === "evidence_submitted" && (!draftFor(item.id).summary.trim() || evidenceFrom(draftFor(item.id).evidence).length === 0))} onClick={() => void save("transition_data_quality", { id: item.id, to_status: next, correction_summary: draftFor(item.id).summary, evidence: evidenceFrom(draftFor(item.id).evidence) })}>{next === "evidence_submitted" ? "提交纠偏证据" : "开始处理"}</button>}{isPmo && item.status === "evidence_submitted" && <><button className="btn-primary" disabled={saving || !draftFor(item.id).comment.trim()} onClick={() => void save("transition_data_quality", { id: item.id, to_status: "closed", comment: draftFor(item.id).comment })}>复核通过并关闭</button><button className="btn-secondary" disabled={saving || !draftFor(item.id).comment.trim()} onClick={() => void save("transition_data_quality", { id: item.id, to_status: "reopened", comment: draftFor(item.id).comment })}>退回重新纠偏</button></>}</div></article>; })}</div>}</section>

        {isPmo && <section className="card" style={{ marginTop: 16 }}><div className="section-title">🔗 跨项目依赖登记</div><div style={{ display: "grid", gridTemplateColumns: "repeat(4,minmax(0,1fr))", gap: 8 }}><select className="input" value={dependency.from_project_id} onChange={event => setDependency({ ...dependency, from_project_id: event.target.value })}>{center.portfolioHealth.map(project => <option key={project.id} value={project.id}>{project.name}</option>)}</select><select className="input" value={dependency.to_project_id} onChange={event => setDependency({ ...dependency, to_project_id: event.target.value })}>{center.portfolioHealth.map(project => <option key={project.id} value={project.id}>{project.name}</option>)}</select><select className="input" value={dependency.owner_user_id} onChange={event => setDependency({ ...dependency, owner_user_id: event.target.value })}>{center.eligibleOwners.map(owner => <option key={owner.id} value={owner.id}>{owner.name}</option>)}</select><input className="input" type="date" value={dependency.due_date} onChange={event => setDependency({ ...dependency, due_date: event.target.value })}/><input className="input" placeholder="依赖描述" value={dependency.description} onChange={event => setDependency({ ...dependency, description: event.target.value })}/><input className="input" placeholder="解除标准" value={dependency.resolution_criteria} onChange={event => setDependency({ ...dependency, resolution_criteria: event.target.value })}/><select className="input" value={dependency.dependency_type} onChange={event => setDependency({ ...dependency, dependency_type: event.target.value })}><option value="deliverable">交付物</option><option value="schedule">进度</option><option value="resource">资源</option><option value="cash">现金</option><option value="technical">技术</option><option value="commercial">商务</option></select><button className="btn-primary" disabled={saving || !dependency.description || !dependency.resolution_criteria || dependency.from_project_id === dependency.to_project_id || !dependency.owner_user_id} onClick={() => void save("create_dependency", dependency)}>登记依赖</button></div></section>}

        <section className="card" style={{ marginTop: 16 }}><div className="section-title">⛓️ 依赖确认与解除</div>{center.dependencies.length === 0 ? <p style={{ color: "var(--text2)" }}>当前范围没有已登记依赖。</p> : <div style={{ display: "grid", gap: 10 }}>{center.dependencies.map(item => { const next = nextStatus(item.status, "dependency"); return <article key={item.id} style={{ border: "1px solid var(--border)", borderRadius: 10, padding: 12 }}><div style={{ display: "flex", justifyContent: "space-between", gap: 8 }}><strong>{projectsById.get(item.fromProjectId) || item.fromProjectId} → {projectsById.get(item.toProjectId) || item.toProjectId}</strong><span className="tag tag-blue">{item.status}</span></div><p style={{ color: "var(--text2)", marginTop: 6 }}>{item.description} · 解除标准：{item.resolutionCriteria}</p><p style={{ fontSize: ".75rem", color: "var(--text3)" }}>责任人：{ownerName(center.eligibleOwners, item.ownerUserId)} · deadline {item.dueDate}</p><WorkFields id={item.id}/><div style={{ display: "flex", gap: 7, marginTop: 8, flexWrap: "wrap" }}>{next && ownerCanAct(item.ownerUserId) && <button className="btn-primary" disabled={saving || (next === "evidence_submitted" && evidenceFrom(draftFor(item.id).evidence).length === 0)} onClick={() => void save("transition_dependency", { id: item.id, to_status: next, evidence: evidenceFrom(draftFor(item.id).evidence), comment: draftFor(item.id).comment })}>{next === "evidence_submitted" ? "提交解除证据" : next === "confirmed" ? "确认依赖" : "开始监督"}</button>}{isPmo && item.status === "evidence_submitted" && <><button className="btn-primary" disabled={!draftFor(item.id).comment.trim()} onClick={() => void save("transition_dependency", { id: item.id, to_status: "verified", comment: draftFor(item.id).comment })}>核验解除证据</button><button className="btn-secondary" disabled={!draftFor(item.id).comment.trim()} onClick={() => void save("transition_dependency", { id: item.id, to_status: "reopened", comment: draftFor(item.id).comment })}>证据不足，退回</button></>}{isPmo && item.status === "verified" && <button className="btn-primary" disabled={!draftFor(item.id).comment.trim()} onClick={() => void save("transition_dependency", { id: item.id, to_status: "resolved", comment: draftFor(item.id).comment })}>确认解除</button>}</div></article>; })}</div>}</section>

        {isPmo && <section className="card" style={{ marginTop: 16 }}><div className="section-title">👥 8–12 周资源计划</div><div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}><select className="input" value={capacity.owner_user_id} onChange={event => { const owner = center.eligibleOwners.find(item => item.id === event.target.value); setCapacity({ ...capacity, owner_user_id: event.target.value, owner_name: owner?.name || "" }); }}>{center.eligibleOwners.map(owner => <option key={owner.id} value={owner.id}>{owner.name}</option>)}</select><input className="input" placeholder="关键角色，如解决方案架构师" value={capacity.role_name} onChange={event => setCapacity({ ...capacity, role_name: event.target.value })}/><div style={{ display: "flex", gap: 7 }}><button className="btn-secondary" disabled={capacityWeeks.length <= 8} onClick={() => setCapacityWeeks(previous => previous.slice(0, -1))}>减一周</button><button className="btn-secondary" disabled={capacityWeeks.length >= 12} onClick={() => setCapacityWeeks(previous => [...previous, buildWeeks(center.portfolioHealth, previous.length + 1).at(-1)!])}>加一周</button></div></div><div style={{ overflowX: "auto", marginTop: 10 }}><table style={{ width: "100%", borderCollapse: "collapse", minWidth: 900 }}><thead><tr><th style={{ textAlign: "left" }}>周期</th><th>可用工时</th>{center.portfolioHealth.map(project => <th key={project.id}>{project.name}</th>)}</tr></thead><tbody>{capacityWeeks.map((week, index) => <tr key={week.period_start}><td>{week.period_start} 至 {week.period_end}</td><td><input className="input" type="number" min="0" value={week.capacity_hours} onChange={event => setCapacityWeeks(previous => previous.map((entry, i) => i === index ? { ...entry, capacity_hours: event.target.value } : entry))}/></td>{center.portfolioHealth.map(project => <td key={project.id}><input className="input" type="number" min="0" value={week.allocations[project.id] || "0"} onChange={event => setCapacityWeeks(previous => previous.map((entry, i) => i === index ? { ...entry, allocations: { ...entry.allocations, [project.id]: event.target.value } } : entry))}/></td>)}</tr>)}</tbody></table></div><button className="btn-primary" style={{ marginTop: 10 }} disabled={saving || !capacity.owner_user_id || !capacity.role_name || capacityWeeks.length < 8} onClick={() => void save("save_capacity_plan", { ...capacity, weeks: capacityWeeks.map(week => ({ ...week, allocations: Object.entries(week.allocations).filter(([, hours]) => Number(hours) > 0).map(([project_id, hours]) => ({ project_id, hours: Number(hours) })) })) })}>保存资源计划并识别冲突</button></section>}

        <section className="card" style={{ marginTop: 16 }}><div className="section-title">🛠️ 资源冲突处置</div>{center.capacityConflictActions.length === 0 ? <p style={{ color: "var(--text2)" }}>当前没有未关闭资源冲突行动。</p> : <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(310px,1fr))", gap: 10 }}>{center.capacityConflictActions.map(item => { const next = nextStatus(item.status, "capacity"); return <article key={item.id} style={{ border: "1px solid var(--border)", borderRadius: 10, padding: 12 }}><div style={{ display: "flex", justifyContent: "space-between" }}><strong>{item.actionTitle}</strong><span className="tag tag-red">超载 {item.overloadHours}h · {item.status}</span></div><p style={{ color: "var(--text2)", marginTop: 6 }}>责任人：{ownerName(center.eligibleOwners, item.ownerUserId)} · deadline {item.dueAt}</p><WorkFields id={item.id} actionPlan/><div style={{ display: "flex", gap: 7, marginTop: 8, flexWrap: "wrap" }}>{next && ownerCanAct(item.ownerUserId) && <button className="btn-primary" disabled={saving || (next === "evidence_submitted" && (!draftFor(item.id).actionPlan.trim() || evidenceFrom(draftFor(item.id).evidence).length === 0))} onClick={() => void save("transition_capacity_conflict", { id: item.id, to_status: next, action_plan: draftFor(item.id).actionPlan, evidence: evidenceFrom(draftFor(item.id).evidence) })}>{next === "evidence_submitted" ? "提交处置证据" : "开始处置"}</button>}{isPmo && item.status === "evidence_submitted" && <><button className="btn-primary" disabled={!draftFor(item.id).comment.trim()} onClick={() => void save("transition_capacity_conflict", { id: item.id, to_status: "verified", comment: draftFor(item.id).comment })}>核验冲突已消除</button><button className="btn-secondary" disabled={!draftFor(item.id).comment.trim()} onClick={() => void save("transition_capacity_conflict", { id: item.id, to_status: "reopened", comment: draftFor(item.id).comment })}>退回重做</button></>}{isPmo && item.status === "verified" && <button className="btn-primary" onClick={() => void save("transition_capacity_conflict", { id: item.id, to_status: "closed" })}>关闭冲突</button>}</div></article>; })}</div>}</section>

        <section className="card" style={{ marginTop: 16 }}><div className="section-title">✅ 会后治理行动</div>{center.governanceActions.length === 0 ? <p style={{ color: "var(--text2)" }}>当前没有会后行动。</p> : <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(310px,1fr))", gap: 10 }}>{center.governanceActions.map(item => { const next = nextStatus(item.status, "governance"); return <article key={item.id} style={{ border: "1px solid var(--border)", borderRadius: 10, padding: 12 }}><div style={{ display: "flex", justifyContent: "space-between" }}><strong>{item.title}</strong><span className="tag tag-blue">{item.status}</span></div><p style={{ color: "var(--text2)", marginTop: 6 }}>责任人：{ownerName(center.eligibleOwners, item.ownerUserId)} · deadline {item.dueAt}</p><WorkFields id={item.id}/><div style={{ display: "flex", gap: 7, marginTop: 8, flexWrap: "wrap" }}>{next && ownerCanAct(item.ownerUserId) && <button className="btn-primary" disabled={saving || (next === "evidence_submitted" && evidenceFrom(draftFor(item.id).evidence).length === 0)} onClick={() => void save("transition_governance_action", { id: item.id, to_status: next, evidence: evidenceFrom(draftFor(item.id).evidence) })}>{next === "evidence_submitted" ? "提交完成证据" : "接收并执行"}</button>}{isPmo && item.status === "evidence_submitted" && <><button className="btn-primary" disabled={!draftFor(item.id).comment.trim()} onClick={() => void save("transition_governance_action", { id: item.id, to_status: "effect_review", effect_review: { outcome: "effective", summary: draftFor(item.id).comment }, comment: draftFor(item.id).comment })}>完成效果复核</button><button className="btn-secondary" disabled={!draftFor(item.id).comment.trim()} onClick={() => void save("transition_governance_action", { id: item.id, to_status: "reopened", comment: draftFor(item.id).comment })}>效果未达成，重开</button></>}{isPmo && item.status === "effect_review" && <><button className="btn-primary" onClick={() => void save("transition_governance_action", { id: item.id, to_status: "closed" })}>关闭行动</button><button className="btn-secondary" disabled={!draftFor(item.id).comment.trim()} onClick={() => void save("transition_governance_action", { id: item.id, to_status: "reopened", comment: draftFor(item.id).comment })}>效果未达成，重开</button></>}</div></article>; })}</div>}</section>

        {isPmo && <section className="card" style={{ marginTop: 16 }}><div className="section-title">📐 版本化指标字典</div><p style={{ color: "var(--text2)", marginBottom: 10 }}>指标必须明确口径、来源和数据新鲜度；规则矩阵只能引用已生效指标版本。</p><div style={{ display: "grid", gridTemplateColumns: "repeat(4,minmax(0,1fr))", gap: 8 }}><input className="input" placeholder="指标编码" value={metric.metric_key} onChange={event => setMetric({ ...metric, metric_key: event.target.value })}/><input className="input" placeholder="版本，如 v1" value={metric.version} onChange={event => setMetric({ ...metric, version: event.target.value })}/><input className="input" placeholder="指标名称" value={metric.name} onChange={event => setMetric({ ...metric, name: event.target.value })}/><input className="input" type="number" min="1" placeholder="新鲜度SLA（分钟）" value={metric.freshness_sla_minutes} onChange={event => setMetric({ ...metric, freshness_sla_minutes: event.target.value })}/><textarea className="input" rows={2} placeholder="完整口径定义" value={metric.definition} onChange={event => setMetric({ ...metric, definition: event.target.value })}/><input className="input" placeholder="分子定义（可选）" value={metric.numerator_definition} onChange={event => setMetric({ ...metric, numerator_definition: event.target.value })}/><input className="input" placeholder="分母定义（可选）" value={metric.denominator_definition} onChange={event => setMetric({ ...metric, denominator_definition: event.target.value })}/><input className="input" placeholder="数据来源，如飞书项目台账" value={metric.source_type} onChange={event => setMetric({ ...metric, source_type: event.target.value })}/><input className="input" placeholder="字段或计算公式" value={metric.field_or_formula} onChange={event => setMetric({ ...metric, field_or_formula: event.target.value })}/><input className="input" placeholder="单位" value={metric.unit} onChange={event => setMetric({ ...metric, unit: event.target.value })}/><label style={{ display: "flex", alignItems: "center", gap: 7 }}><input type="checkbox" checked={metric.activate} onChange={event => setMetric({ ...metric, activate: event.target.checked })}/>审批并立即生效</label><button className="btn-primary" disabled={saving || !metric.metric_key || !metric.version || !metric.name || !metric.definition || !metric.source_type || !metric.field_or_formula || !metric.freshness_sla_minutes} onClick={() => void save("save_metric_definition", metric)}>保存指标版本</button></div><div style={{ marginTop: 10, display: "flex", gap: 7, flexWrap: "wrap" }}>{center.metricDefinitions.map(item => <span key={item.id} className="tag tag-green">{item.name} · {item.metricKey}@{item.version} · {item.freshnessSlaMinutes ?? "?"}分钟</span>)}</div></section>}

        {isPmo && <section className="card" style={{ marginTop: 16 }}><div className="section-title">🧩 S/A/B/C分级规则矩阵</div><p style={{ color: "var(--text2)", lineHeight: 1.7 }}>每个等级的每条信号均明确比较方式、黄/红阈值、影响维度、数据过期阈值、处理角色、SLA起止点、升级层级、决策权限和关闭证据。</p>{center.metricDefinitions.length === 0 && <p style={{ color: "var(--amber)", marginTop: 8 }}>请先在上方建立并生效指标字典，再配置信号规则。</p>}<div style={{ display: "grid", gap: 14, marginTop: 12 }}>{LEVELS.map(level => <article key={level} style={{ border: "1px solid var(--border)", borderRadius: 12, padding: 12 }}><h3>{level}级项目</h3><div style={{ display: "grid", gridTemplateColumns: "repeat(4,minmax(0,1fr))", gap: 7 }}><input className="input" type="number" min="0" placeholder="最大开放关键信号数" value={rules[level].maxOpenCriticalSignals} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], maxOpenCriticalSignals: event.target.value } }))}/><input className="input" placeholder="治理节奏" value={rules[level].cadence} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], cadence: event.target.value } }))}/><input className="input" type="number" min="1" placeholder="升级时限（小时）" value={rules[level].escalationHours} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], escalationHours: event.target.value } }))}/><label style={{ display: "flex", alignItems: "center", gap: 7 }}><input type="checkbox" checked={rules[level].evidenceRequired} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], evidenceRequired: event.target.checked } }))}/>关闭必须有证据</label></div>{rules[level].signalRules.map((rule, index) => <div key={index} style={{ background: "var(--surface2)", borderRadius: 10, padding: 10, marginTop: 9 }}><div style={{ display: "grid", gridTemplateColumns: "repeat(4,minmax(0,1fr))", gap: 7 }}><select className="input" value={rule.signalType} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, signalType: event.target.value } : entry) } }))}><option value="">选择信号类型</option>{SIGNAL_TYPES.map(item => <option key={item} value={item}>{item}</option>)}</select><select className="input" value={rule.metricRef} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, metricRef: event.target.value } : entry) } }))}><option value="">选择指标版本</option>{center.metricDefinitions.map(item => <option key={item.id} value={`${item.metricKey}@@${item.version}`}>{item.name}@{item.version}</option>)}</select><select className="input" value={rule.comparison} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, comparison: event.target.value } : entry) } }))}><option value="greater_than">数值越大越危险</option><option value="less_than">数值越小越危险</option><option value="variance_percent_above">偏差百分比越大越危险</option></select><span style={{ color: "var(--text2)", fontSize: ".72rem", alignSelf: "center" }}>{rule.comparison === "less_than" ? "红色阈值应小于或等于黄色阈值" : "黄色阈值应小于或等于红色阈值"}</span><input className="input" type="number" placeholder="黄色阈值" value={rule.yellowThreshold} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, yellowThreshold: event.target.value } : entry) } }))}/><input className="input" type="number" placeholder="红色阈值" value={rule.redThreshold} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, redThreshold: event.target.value } : entry) } }))}/><input className="input" placeholder="阈值单位" value={rule.unit} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, unit: event.target.value } : entry) } }))}/><input className="input" placeholder="影响维度，用、分隔" value={rule.impactDimensions} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, impactDimensions: event.target.value } : entry) } }))}/><input className="input" type="number" placeholder="数据新鲜度（小时）" value={rule.dataFreshnessHours} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, dataFreshnessHours: event.target.value } : entry) } }))}/><input className="input" placeholder="处理角色" value={rule.handlingRole} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, handlingRole: event.target.value } : entry) } }))}/><input className="input" placeholder="SLA起点" value={rule.slaStartEvent} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, slaStartEvent: event.target.value } : entry) } }))}/><input className="input" placeholder="SLA终点" value={rule.slaEndEvent} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, slaEndEvent: event.target.value } : entry) } }))}/><input className="input" placeholder="升级层级，如L2" value={rule.escalationLevel} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, escalationLevel: event.target.value } : entry) } }))}/><input className="input" placeholder="决策权限" value={rule.decisionAuthority} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, decisionAuthority: event.target.value } : entry) } }))}/><input className="input" style={{ gridColumn: "span 3" }} placeholder="关闭证据，用、分隔" value={rule.closureEvidence} onChange={event => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.map((entry, i) => i === index ? { ...entry, closureEvidence: event.target.value } : entry) } }))}/>{rules[level].signalRules.length > 1 && <button className="btn-secondary" onClick={() => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: previous[level].signalRules.filter((_, i) => i !== index) } }))}>删除此规则</button>}</div></div>)}<button className="btn-secondary" style={{ marginTop: 8 }} onClick={() => setRules(previous => ({ ...previous, [level]: { ...previous[level], signalRules: [...previous[level].signalRules, { ...EMPTY_SIGNAL_RULE }] } }))}>新增信号规则</button></article>)}</div><div style={{ display: "grid", gridTemplateColumns: "1fr 2fr auto", gap: 8, marginTop: 12 }}><input className="input" placeholder="矩阵版本" value={ruleVersion} onChange={event => setRuleVersion(event.target.value)}/><input className="input" placeholder="变更原因" value={ruleReason} onChange={event => setRuleReason(event.target.value)}/><button className="btn-primary" disabled={saving || !ruleVersion || !ruleReason || center.metricDefinitions.length === 0} onClick={() => void save("save_rule_matrix", { version: ruleVersion, change_reason: ruleReason, activate: true, rules: Object.fromEntries(LEVELS.map(level => [level, { maxOpenCriticalSignals: Number(rules[level].maxOpenCriticalSignals), cadence: rules[level].cadence, escalationHours: Number(rules[level].escalationHours), evidenceRequired: rules[level].evidenceRequired, signalRules: rules[level].signalRules.map(rule => { const [metricKey, metricVersion] = rule.metricRef.split("@@"); return { signalType: rule.signalType, metricKey, metricVersion, comparison: rule.comparison, yellowThreshold: Number(rule.yellowThreshold), redThreshold: Number(rule.redThreshold), unit: rule.unit, impactDimensions: rule.impactDimensions.split(/[、,]/).map(value => value.trim()).filter(Boolean), dataFreshnessHours: Number(rule.dataFreshnessHours), handlingRole: rule.handlingRole, slaStartEvent: rule.slaStartEvent, slaEndEvent: rule.slaEndEvent, escalationLevel: rule.escalationLevel, decisionAuthority: rule.decisionAuthority, closureEvidence: rule.closureEvidence.split(/[、,]/).map(value => value.trim()).filter(Boolean) }; }) }])) })}>审批并启用规则矩阵</button></div></section>}
      </>}
    </div>
  </main>;
}
